"use client";

import { useEffect, useState } from "react";
import { ChevronDown, Search } from "lucide-react";

const heroImages = ["/images/hero/Hero2.webp", "/images/hero/Hero3.jpg"];
const categories = ["All Categories", "Acts", "Citizen Engagements", "Directory", "Explore India", "News", "Schemes", "Services"];
const trendingSearches = ["Apply Aadhaar", "DigiLocker", "New Voter Registration", "Tatkaal Passport Service", "Driving Licence"];

export default function Hero() {
  const [currentSlide, setCurrentSlide] = useState(0);

  useEffect(() => {
    const timer = window.setInterval(() => setCurrentSlide((value) => (value + 1) % heroImages.length), 6500);
    return () => window.clearInterval(timer);
  }, []);

  return (
    <section id="main-content" className="relative isolate min-h-[500px] overflow-hidden sm:min-h-[540px]">
      {heroImages.map((src, index) => (
        <div key={src} className="absolute inset-0 bg-cover bg-center transition-opacity duration-1000" style={{ backgroundImage: `url(${src})`, opacity: index === currentSlide ? 1 : 0 }} aria-hidden="true" />
      ))}
      <div className="absolute inset-0 bg-[linear-gradient(180deg,rgba(4,20,52,.68),rgba(4,22,56,.82)_45%,rgba(5,24,55,.7))]" />
      <div className="relative mx-auto flex min-h-[500px] max-w-[1200px] flex-col items-center justify-center px-4 py-12 text-center sm:min-h-[540px] sm:px-6">
        <div className="mx-auto max-w-[820px]">
          <p className="text-xs font-bold uppercase tracking-[.28em] text-[#ffb65c]">National Portal of India</p>
          <h1 className="mx-auto mt-4 max-w-3xl text-4xl font-bold leading-tight text-white sm:text-5xl">Where Government Information Converges</h1>
          <p className="mx-auto mt-4 max-w-2xl text-sm leading-6 text-white/84 sm:text-base">One trusted destination for public services, schemes and information from the Government of India.</p>
          <div className="mx-auto mt-8 flex max-w-[760px] flex-col overflow-hidden rounded-md bg-white shadow-[0_18px_50px_rgba(0,0,0,.3)] sm:flex-row">
            <div className="flex min-w-0 flex-1 items-center gap-2 px-4">
              <Search size={19} className="text-slate-400" />
              <label htmlFor="hero-search" className="sr-only">Search India Portal</label>
              <input id="hero-search" type="search" placeholder="What are you looking for?" className="h-14 w-full bg-transparent text-sm text-slate-800 outline-none sm:text-base" />
            </div>
            <div className="relative border-t border-slate-200 sm:border-l sm:border-t-0">
              <label htmlFor="hero-category" className="sr-only">Search category</label>
              <select id="hero-category" defaultValue="All Categories" className="h-14 w-full appearance-none bg-white pl-4 pr-9 text-sm text-slate-700 outline-none sm:w-[165px]">
                {categories.map((category) => <option key={category}>{category}</option>)}
              </select>
              <ChevronDown size={16} className="pointer-events-none absolute right-3 top-1/2 -translate-y-1/2 text-slate-500" />
            </div>
            <button type="button" className="h-14 bg-[#d83232] px-8 font-bold text-white transition hover:bg-[#b82127]">Search</button>
          </div>
          <div className="mt-6 flex flex-wrap items-center justify-center gap-2">
            <span className="mr-1 text-xs font-semibold text-white/75">Trending:</span>
            {trendingSearches.map((term) => <button key={term} type="button" className="rounded-full border border-white/35 bg-white/10 px-3 py-1.5 text-xs text-white backdrop-blur-sm transition hover:bg-white/20">{term}</button>)}
          </div>
        </div>
        <div className="absolute bottom-5 right-5 flex gap-2 sm:right-8">
          {heroImages.map((_, index) => <button key={index} type="button" onClick={() => setCurrentSlide(index)} aria-label={`Show slide ${index + 1}`} className={`h-2 rounded-full transition-all ${index === currentSlide ? "w-8 bg-[#ff9933]" : "w-2 bg-white/60"}`} />)}
        </div>
      </div>
    </section>
  );
}
