"use client";

import Image from "next/image";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { useState } from "react";

const services = [
  {
    title: "Online textbooks of National Council of Educational Research and Training",
    image: "/images/hero/Hero2.webp",
  },
  {
    title: "Interact with Hon'ble Prime Minister of India",
    image: "/images/hero/Hero1.webp",
  },
  {
    title: "National Career Service for Job Seekers and Employers",
    image: "/images/hero/Hero3.jpg",
  },
  {
    title: "DigiLocker — Access Documents Anywhere, Anytime",
    image: "/images/hero/Hero1.webp",
  },
];

export default function OnlineServices() {
  const [activeIndex, setActiveIndex] = useState(0);

  const visible = Array.from({ length: 3 }, (_, i) => {
    return services[(activeIndex + i) % services.length];
  });

  return (
    <section id="services" className="relative bg-[#eef1f6] pb-16 pt-4">
      <div
        className="pointer-events-none absolute inset-0 opacity-[0.06]"
        style={{
          backgroundImage: "url('/images/hero/Hero2.webp')",
          backgroundSize: "cover",
          backgroundPosition: "center top",
          filter: "blur(2px)",
        }}
        aria-hidden="true"
      />

      <div className="relative mx-auto max-w-[1200px] px-4 sm:px-6">
        <div className="glass-card overflow-hidden rounded-xl shadow-[0_12px_40px_rgba(10,42,110,0.1)]">
          <div className="grid lg:grid-cols-[260px_1fr]">
            <div className="flex flex-col justify-between bg-[#e31e24] p-7 text-white sm:p-8">
              <div>
                <h2 className="text-[2rem] font-bold leading-[1.15] tracking-tight">
                  Online
                  <br />
                  Services
                </h2>
                <div className="mt-3 h-[3px] w-14 bg-white" />
                <p className="mt-5 text-sm leading-relaxed text-white/90">
                  Avail online services &amp; Save time
                </p>
              </div>
              <button
                type="button"
                className="mt-8 w-fit rounded-full bg-white px-7 py-2 text-sm font-semibold text-gray-900 transition-transform duration-300 hover:scale-[1.03]"
              >
                View All
              </button>
            </div>

            <div className="relative bg-white/90 p-5 sm:p-7">
              <div className="grid gap-4 sm:grid-cols-3">
                {visible.map((service) => (
                  <article
                    key={service.title}
                    className="group cursor-pointer overflow-hidden rounded-lg border border-gray-100 bg-white shadow-sm transition-all duration-300 hover:-translate-y-1 hover:shadow-md"
                  >
                    <div className="relative h-36 overflow-hidden sm:h-[148px]">
                      <Image
                        src={service.image}
                        alt=""
                        fill
                        sizes="(max-width: 768px) 100vw, 33vw"
                        className="object-cover transition-transform duration-500 group-hover:scale-105"
                      />
                    </div>
                    <div className="p-3.5 sm:p-4">
                      <h3 className="line-clamp-3 text-[13px] font-medium leading-snug text-gray-800">
                        {service.title}
                      </h3>
                    </div>
                  </article>
                ))}
              </div>

              <div className="mt-5 flex items-center justify-end gap-2">
                <button
                  type="button"
                  onClick={() =>
                    setActiveIndex((i) => (i === 0 ? services.length - 1 : i - 1))
                  }
                  aria-label="Previous services"
                  className="flex h-8 w-8 items-center justify-center rounded-full border border-gray-300 text-gray-600 transition-colors hover:border-[#0a2a6e] hover:text-[#0a2a6e]"
                >
                  <ChevronLeft size={16} />
                </button>
                <button
                  type="button"
                  onClick={() =>
                    setActiveIndex((i) => (i === services.length - 1 ? 0 : i + 1))
                  }
                  aria-label="Next services"
                  className="flex h-8 w-8 items-center justify-center rounded-full border border-gray-300 text-gray-600 transition-colors hover:border-[#0a2a6e] hover:text-[#0a2a6e]"
                >
                  <ChevronRight size={16} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
